"use client"

import { Card, CardContent } from "@/components/ui/card"
import { Barcode, CheckCircle2, XCircle, Percent } from "lucide-react"

interface BarcodeStatsProps {
  total: number
  used: number
  available: number
}

export function BarcodeStats({ total, used, available }: BarcodeStatsProps) {
  const usageRate = total > 0 ? Math.round((used / total) * 100) : 0

  const stats = [
    {
      label: "Total Barcodes",
      value: total.toLocaleString(),
      icon: Barcode,
      color: "text-foreground",
    },
    {
      label: "Available",
      value: available.toLocaleString(),
      icon: CheckCircle2,
      color: "text-success",
    },
    {
      label: "Used",
      value: used.toLocaleString(),
      icon: XCircle,
      color: "text-muted-foreground",
    },
    {
      label: "Usage Rate",
      value: `${usageRate}%`,
      icon: Percent,
      color: "text-warning",
    },
  ]

  return (
    <div className="grid grid-cols-2 gap-4 lg:grid-cols-4">
      {stats.map((stat) => (
        <Card key={stat.label} className="bg-card border-border">
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">{stat.label}</p>
                <p className={`text-2xl font-semibold mt-1 ${stat.color}`}>
                  {stat.value}
                </p>
              </div>
              <stat.icon className={`h-8 w-8 ${stat.color} opacity-50`} />
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  )
}
